package org.example;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

/**
 * PaymentOrchestrationApplication — Spring Boot 3.x entry point.
 *
 * <p>{@code @SpringBootApplication} is a convenience annotation that combines:
 * <ul>
 *   <li>{@code @Configuration}          — marks this class as a source of bean definitions</li>
 *   <li>{@code @EnableAutoConfiguration} — lets Spring Boot auto-configure beans based on
 *       classpath dependencies (e.g., DataSource, RedisTemplate, KafkaTemplate)</li>
 *   <li>{@code @ComponentScan}           — scans the {@code org.example} package and all
 *       sub-packages for Spring-managed components</li>
 * </ul>
 */
@SpringBootApplication
public class PaymentOrchestrationApplication {

    public static void main(String[] args) {
        SpringApplication.run(PaymentOrchestrationApplication.class, args);
    }
}

package org.example.provider;

import lombok.extern.slf4j.Slf4j;
import org.example.exception.ProviderException;

import java.math.BigDecimal;
import java.util.Random;
import java.util.UUID;

/**
 * AbstractSimulatedProviderConnector — shared simulation logic for all provider connectors.
 *
 * <h2>Purpose</h2>
 * <p>Both {@link ProviderAConnector} and {@link ProviderBConnector} simulate an ~20%
 * provider failure rate to exercise the Kafka retry and DLT paths during local development.
 * This base class centralises that simulation logic so it is defined exactly once (DRY).
 *
 * <h2>Failure Simulation</h2>
 * <ul>
 *   <li>~20% of calls throw a {@link ProviderException}.</li>
 *   <li>The failure mode is randomly chosen between 504 Gateway Timeout and
 *       500 Internal Server Error to simulate real-world transient variance.</li>
 * </ul>
 *
 * <h2>Subclass Contract</h2>
 * <p>Concrete subclasses must implement:
 * <ul>
 *   <li>{@link #getProviderId()} — returns the unique provider identifier (e.g., "PROVIDER_A")</li>
 *   <li>{@link #getTxnRefPrefix()} — returns the prefix for mock transaction references
 *       (e.g., "PROVA" → reference will look like "PROVA-ABC123DEF456")</li>
 * </ul>
 */
@Slf4j
public abstract class AbstractSimulatedProviderConnector implements PaymentProviderConnector {

    /**
     * Failure probability: 20% of calls will throw a {@link ProviderException}.
     * Adjust this constant in a subclass or here to control retry path coverage.
     */
    private static final double FAILURE_RATE = 0.20;

    /**
     * Thread-safe random instance for failure simulation.
     * {@code java.util.Random} is sufficient — no cryptographic randomness needed here.
     */
    private final Random random = new Random();

    /**
     * Returns the transaction reference prefix for this provider.
     * Used to construct a mock provider transaction ID on successful processing.
     * <p>Example: "PROVA" → produces transaction refs like "PROVA-ABC123DEF456GHIJ"
     *
     * @return non-null prefix string (e.g., "PROVA", "PROVB")
     */
    protected abstract String getTxnRefPrefix();

    /**
     * Simulates an HTTP call to the external payment provider.
     *
     * <ol>
     *   <li>Generates a random double in [0.0, 1.0)</li>
     *   <li>If the value is below {@link #FAILURE_RATE}, simulates a transient failure</li>
     *   <li>Randomly chooses between 504 (timeout) and 500 (server error) failure modes</li>
     *   <li>Otherwise returns a mock provider reference ID as if the call succeeded</li>
     * </ol>
     *
     * @param paymentId the UUID of the payment
     * @param amount    the payment amount
     * @param currency  the ISO 4217 currency code
     * @return a mock provider transaction reference on success
     * @throws ProviderException on simulated 504 or 500 failure
     */
    @Override
    public String processPayment(String paymentId, BigDecimal amount, String currency) {
        log.debug("[{}] Attempting to process payment [{}], amount={} {}",
                getProviderId(), paymentId, amount, currency);

        // ── FAILURE SIMULATION ────────────────────────────────────────────────
        double roll = random.nextDouble();
        if (roll < FAILURE_RATE) {
            boolean isTimeout = random.nextBoolean();
            if (isTimeout) {
                log.warn("[{}] Simulated 504 Gateway Timeout for payment [{}]",
                        getProviderId(), paymentId);
                throw new ProviderException(
                        getProviderId(),
                        "504 Gateway Timeout: " + getProviderId()
                                + " did not respond within the deadline for payment " + paymentId
                );
            } else {
                log.warn("[{}] Simulated 500 Internal Server Error for payment [{}]",
                        getProviderId(), paymentId);
                throw new ProviderException(
                        getProviderId(),
                        "500 Internal Server Error: " + getProviderId()
                                + " encountered an internal fault while processing payment " + paymentId
                );
            }
        }

        // ── SUCCESS PATH ──────────────────────────────────────────────────────
        // Generate a deterministic-looking mock transaction reference.
        // In a real integration, this would be the txn ID from the provider's API response.
        String providerTxnRef = getTxnRefPrefix() + "-"
                + UUID.randomUUID().toString().replace("-", "").substring(0, 16).toUpperCase();

        log.info("[{}] Successfully processed payment [{}]. Provider reference: {}",
                getProviderId(), paymentId, providerTxnRef);
        return providerTxnRef;
    }
}

package org.example.provider;

import lombok.extern.slf4j.Slf4j;
import org.example.exception.ProviderException;
import org.springframework.stereotype.Component;

import java.math.BigDecimal;
import java.util.Random;
import java.util.UUID;

/**
 * ProviderAConnector — simulates integration with Payment Provider A.
 *
 * <p>This connector is selected by the {@code RoutingEngine} when the payment method
 * is {@code CARD}.
 *
 * <h2>Failure Simulation Logic</h2>
 * <p>To force the retry and DLQ infrastructure to activate, this connector intentionally
 * fails ~20% of calls.  The failure mode is randomly chosen between:
 * <ul>
 *   <li><strong>504 Gateway Timeout</strong>: The upstream provider took too long to respond.</li>
 *   <li><strong>500 Internal Server Error</strong>: The upstream provider returned a server fault.</li>
 * </ul>
 * This mirrors real-world transient failures that should be retried.
 */
@Slf4j
@Component
public class ProviderAConnector implements PaymentProviderConnector {

    private static final String PROVIDER_ID = "PROVIDER_A";

    /**
     * Failure probability: 20% of calls will throw a {@code ProviderException}.
     * Adjust this constant to control retry path coverage during local testing.
     */
    private static final double FAILURE_RATE = 0.20;

    /**
     * Thread-safe random instance for simulating provider failures.
     * Using {@code java.util.Random} is sufficient here — we do not need
     * cryptographic randomness for failure simulation.
     */
    private final Random random = new Random();

    @Override
    public String getProviderId() {
        return PROVIDER_ID;
    }

    /**
     * {@inheritDoc}
     *
     * <p>Simulates an HTTP call to Provider A's payment processing endpoint.
     * <ol>
     *   <li>Generate a random double in [0.0, 1.0)</li>
     *   <li>If the value is below {@link #FAILURE_RATE}, simulate a failure</li>
     *   <li>Randomly choose between 504 (timeout) and 500 (server error)</li>
     *   <li>Otherwise, return a mock provider reference ID as if the call succeeded</li>
     * </ol>
     *
     * @param paymentId the UUID of the payment
     * @param amount    the payment amount
     * @param currency  the payment currency
     * @return a mock provider transaction reference (e.g., "PROVA-{uuid}")
     * @throws ProviderException on simulated 504 or 500 error
     */
    @Override
    public String processPayment(String paymentId, BigDecimal amount, String currency) {
        log.debug("[{}] Attempting to process payment [{}], amount={} {}",
                PROVIDER_ID, paymentId, amount, currency);

        // ── FAILURE SIMULATION ───────────────────────────────────────────────
        // Roll a random number; if it falls within the failure window, simulate
        // one of the two common transient provider errors.
        double roll = random.nextDouble();
        if (roll < FAILURE_RATE) {
            // Randomly select between two error modes to simulate real-world variance
            boolean isTimeout = random.nextBoolean();
            if (isTimeout) {
                log.warn("[{}] Simulated 504 Gateway Timeout for payment [{}]",
                        PROVIDER_ID, paymentId);
                throw new ProviderException(
                        PROVIDER_ID,
                        "504 Gateway Timeout: Provider A did not respond within the deadline "
                                + "for payment " + paymentId
                );
            } else {
                log.warn("[{}] Simulated 500 Internal Server Error for payment [{}]",
                        PROVIDER_ID, paymentId);
                throw new ProviderException(
                        PROVIDER_ID,
                        "500 Internal Server Error: Provider A encountered an internal fault "
                                + "while processing payment " + paymentId
                );
            }
        }
        // ── SUCCESS PATH ─────────────────────────────────────────────────────
        // Generate a deterministic-looking mock transaction reference.
        // In a real integration, this would be the txn ID from the provider's API response.
        String providerTxnRef = "PROVA-" + UUID.randomUUID().toString().replace("-", "").substring(0, 16).toUpperCase();
        log.info("[{}] Successfully processed payment [{}]. Provider reference: {}",
                PROVIDER_ID, paymentId, providerTxnRef);
        return providerTxnRef;
    }
}

package org.example.provider;

import org.springframework.stereotype.Component;

/**
 * ProviderAConnector — simulates integration with Payment Provider A.
 *
 * <p>Selected by the {@code RoutingEngine} when the payment method is {@code CARD}.
 *
 * <p>All failure simulation logic (20% failure rate, 504/500 error modes) is inherited
 * from {@link AbstractSimulatedProviderConnector}, keeping this class focused solely on
 * its provider-specific identity.
 */
@Component
public class ProviderAConnector extends AbstractSimulatedProviderConnector {

    private static final String PROVIDER_ID   = "PROVIDER_A";
    private static final String TXN_REF_PREFIX = "PROVA";

    @Override
    public String getProviderId() {
        return PROVIDER_ID;
    }

    @Override
    protected String getTxnRefPrefix() {
        return TXN_REF_PREFIX;
    }
}

